const eventsEl = document.querySelector("#events");
const keyHint = document.querySelector("#keyHint");
const presetHint = document.querySelector("#presetHint");
const providerHint = document.querySelector("#providerHint");
const workspaceName = document.querySelector("#workspaceName");
const newWorkspaceBtn = document.querySelector("#newWorkspaceBtn");
const duplicateWorkspaceBtn = document.querySelector("#duplicateWorkspaceBtn");
const saveWorkspaceBtn = document.querySelector("#saveWorkspaceBtn");
const workspaceHint = document.querySelector("#workspaceHint");
const urlParams = new URLSearchParams(window.location.search);
const workspaceId = urlParams.get("ws") || "default";
const workspaceKey = `seedance.workspace.${workspaceId}`;
let savedMedia = {};
let workspaceSaveTimer = 0;
let providerDefaults = {
  t8star: {
    baseUrl: "https://ai.t8star.cn",
    models: [
      ["doubao-seedance-2-0-260128", "doubao-seedance-2-0-260128"],
      ["doubao-seedance-2-0-fast-260128", "doubao-seedance-2-0-fast-260128"],
    ],
    hint: "使用原有 T8Star 兼容接口，素材会先上传到 /v1/files。",
  },
  volcengine: {
    baseUrl: "https://ark.cn-beijing.volces.com/api/v3",
    models: [
      ["doubao-seedance-2-0-260128", "doubao-seedance-2-0-260128"],
      ["doubao-seedance-2-0-fast-260128", "doubao-seedance-2-0-fast-260128"],
    ],
    hint: "使用豆包官方火山方舟 API。首尾帧模式不能与参考素材混用；本地素材会以 data URL 发送。",
  },
};

function providersFromConfig(providers) {
  const next = {};
  for (const [id, provider] of Object.entries(providers || {})) {
    next[id] = {
      baseUrl: provider.base_url || "",
      models: (provider.models || []).map((item) => {
        if (typeof item === "string") return [item, item];
        return [item.id, item.label || item.id];
      }).filter(([value]) => value),
      hint: provider.hint || "",
      label: provider.label || id,
    };
  }
  return Object.keys(next).length ? next : providerDefaults;
}

function field(name) {
  return form.elements[name] || document.querySelector(`[name="${name}"]`);
}

function updateProviderOptions(preserveBase = true) {
  const provider = field("provider")?.value || "t8star";
  const config = providerDefaults[provider] || providerDefaults.t8star;
  const baseInput = field("base_url");
  const modelInput = field("model");
  const currentModel = modelInput.value;
  const knownBases = Object.values(providerDefaults).map((item) => item.baseUrl);
  if (!preserveBase || !baseInput.value.trim() || knownBases.includes(baseInput.value.trim())) {
    baseInput.value = config.baseUrl;
  }
  modelInput.innerHTML = "";
  for (const [value, label] of config.models) {
    const option = document.createElement("option");
    option.value = value;
    option.textContent = label;
    modelInput.append(option);
  }
  modelInput.value = config.models.some(([value]) => value === currentModel) ? currentModel : config.models[0][0];
  providerHint.textContent = config.hint;
}

function isWorkspaceMode() {
  return workspaceId !== "default";
}

function workspaceLabel() {
  return workspaceName.value.trim() || (isWorkspaceMode() ? `主题 ${workspaceId.slice(0, 6)}` : "默认主题");
}

function collectWorkspaceValues() {
  const values = {};
  for (const item of form.elements) {
    if (!item.name || item.type === "file") continue;
    values[item.name] = item.type === "checkbox" ? (item.checked ? "on" : "") : item.value;
  }
  return values;
}

function mediaSnapshot(media = savedMedia) {
  return JSON.parse(JSON.stringify(media || {}));
}

function localWorkspaceSnapshot() {
  return {
    name: workspaceLabel(),
    values: collectWorkspaceValues(),
    media: mediaSnapshot(),
    saved_at: Date.now(),
  };
}

async function workspaceSnapshot(options = {}) {
  if (!options.persistMedia) return localWorkspaceSnapshot();
  const res = await fetch("/api/workspace/snapshot", { method: "POST", body: formDataWithSavedMedia() });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || "保存主题素材失败");
  applyPreset(data);
  return {
    name: workspaceLabel(),
    values: collectWorkspaceValues(),
    media: mediaSnapshot(data.media),
    saved_at: Date.now(),
  };
}

async function saveWorkspaceDraft(options = {}) {
  const payload = await workspaceSnapshot(options);
  localStorage.setItem(workspaceKey, JSON.stringify(payload));
  workspaceHint.textContent = `已保存草稿：${payload.name}`;
  return payload;
}

function scheduleWorkspaceSave() {
  clearTimeout(workspaceSaveTimer);
  workspaceSaveTimer = setTimeout(saveWorkspaceDraft, 500);
}

function loadWorkspaceDraft() {
  workspaceName.value = isWorkspaceMode() ? workspaceLabel() : "默认主题";
  workspaceHint.textContent = isWorkspaceMode() ? "当前是独立主题页，可与其它主题并发提交" : "默认主题会读取当前保存配置";
  const raw = localStorage.getItem(workspaceKey);
  if (!raw) return false;
  try {
    const draft = JSON.parse(raw);
    workspaceName.value = draft.name || workspaceName.value;
    applyPreset({ values: draft.values || {}, media: draft.media || {} });
    workspaceHint.textContent = `已读取主题草稿：${workspaceName.value}`;
    return true;
  } catch {
    return false;
  }
}

function workspaceUrl(id) {
  const url = new URL(window.location.href);
  url.searchParams.set("ws", id);
  return url.toString();
}

function newWorkspaceId() {
  return `${Date.now().toString(36)}${Math.random().toString(36).slice(2, 8)}`;
}

async function openWorkspace(copyCurrent) {
  const id = newWorkspaceId();
  if (copyCurrent) {
    const current = await saveWorkspaceDraft({ persistMedia: true });
    current.name = `${workspaceLabel()} 副本`;
    localStorage.setItem(`seedance.workspace.${id}`, JSON.stringify(current));
  }
  window.open(workspaceUrl(id), "_blank");
}

function mediaKind(name) {
  if (name.includes("video")) return "video";
  if (name.includes("audio")) return "audio";
  return "image";
}

function renderPreview(drop, kind, url, filename) {
  drop.classList.add("hasPreview");
  drop.querySelector(".preview")?.remove();
  const media = document.createElement(kind === "image" ? "img" : kind);
  media.className = "preview";
  media.src = url;
  if (kind !== "image") media.controls = true;
  if (kind !== "audio") {
    media.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      openPreview(kind, url);
    });
  }
  drop.append(media);
  drop.querySelector("span").textContent = filename || "已上传";
}

function openPreview(kind, url) {
  previewDialogBody.innerHTML = "";
  const media = document.createElement(kind === "image" ? "img" : "video");
  media.src = url;
  if (kind === "video") media.controls = true;
  previewDialogBody.append(media);
  previewDialog.showModal();
}

function clearPreview(drop) {
  drop.classList.remove("hasPreview");
  drop.querySelector(".preview")?.remove();
  drop.querySelector("span").textContent = "未上传";
}

function clearSelectedMedia(input) {
  input.value = "";
  delete savedMedia[input.name];
  clearPreview(input.closest(".drop"));
}

function clearAllMediaInputs() {
  document.querySelectorAll('.drop input[type="file"]').forEach((input) => {
    input.value = "";
    const drop = input.closest(".drop");
    if (drop) clearPreview(drop);
  });
}

function assignFile(input, file) {
  const transfer = new DataTransfer();
  transfer.items.add(file);
  input.files = transfer.files;
  input.dispatchEvent(new Event("change", { bubbles: true }));
}

function wireFileInput(input) {
  if (input.dataset.wired === "1") return;
  input.dataset.wired = "1";
  input.addEventListener("change", () => {
    const drop = input.closest(".drop");
    const file = input.files?.[0];
    if (!file) {
      clearPreview(drop);
      return;
    }
    delete savedMedia[input.name];
    renderPreview(drop, mediaKind(input.name), URL.createObjectURL(file), file.name);
  });

const drop = input.closest(".drop");
  drop.addEventListener("dragover", (event) => {
    event.preventDefault();
    drop.classList.add("isDragging");
  });
  drop.addEventListener("dragleave", () => {
    drop.classList.remove("isDragging");
  });
  drop.addEventListener("drop", (event) => {
    event.preventDefault();
    drop.classList.remove("isDragging");
    const file = event.dataTransfer?.files?.[0];
    if (!file) return;
    if (input.accept && !input.accept.split(",").some((accept) => {
      const rule = accept.trim();
      return rule.endsWith("/*") ? file.type.startsWith(rule.slice(0, -1)) : file.type === rule;
    })) return;
    assignFile(input, file);
  });
}

function makeDrop(name, label, accept) {
  const el = document.createElement("label");
  el.className = "drop";
  el.textContent = label;

const input = document.createElement("input");
  input.name = name;
  input.type = "file";
  input.accept = accept;
  input.setAttribute("form", "jobForm");

const span = document.createElement("span");
  span.textContent = "未上传";

const removeBtn = document.createElement("button");
  removeBtn.className = "removeMediaBtn";
  removeBtn.type = "button";
  removeBtn.textContent = "移除";
  removeBtn.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    clearSelectedMedia(input);
  });

el.append(input, span, removeBtn);
  wireFileInput(input);
  return el;
}

function ensureDropControls(input) {
  const drop = input.closest(".drop");
  if (!drop) return;
  if (!drop.querySelector(".removeMediaBtn")) {
    const removeBtn = document.createElement("button");
    removeBtn.className = "removeMediaBtn";
    removeBtn.type = "button";
    removeBtn.textContent = "移除";
    removeBtn.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      clearSelectedMedia(input);
    });
    drop.append(removeBtn);
  }
  wireFileInput(input);
}

for (let i = 1; i <= 9; i += 1) {
  document.querySelector("#imageRefs").append(makeDrop(`ref_image_${i}`, `@ref_image${i}`, "image/*"));
}
for (let i = 1; i <= 3; i += 1) {
  document.querySelector("#videoRefs").append(makeDrop(`ref_video_${i}`, `参考视频 ${i}`, "video/*"));
  document.querySelector("#audioRefs").append(makeDrop(`ref_audio_${i}`, `参考音频 ${i}`, "audio/*"));
}
document.querySelectorAll('.drop input[type="file"]').forEach(ensureDropControls);

async function loadConfig() {
  const res = await fetch("/api/config");
  const data = await res.json();
  keyHint.textContent = data.has_key ? `已检测到本地 key：${data.masked_key}` : "未检测到本地 key，请手动填写";
  if (data.config_error) {
    keyHint.textContent = `${keyHint.textContent}；供应商配置读取失败，请联系维护者：${data.config_error.detail || data.config_error.message}`;
    submitBtn.disabled = true;
    return;
  }
  providerDefaults = providersFromConfig(data.providers);
  const providerSelect = field("provider");
  const currentProvider = providerSelect.value;
  providerSelect.innerHTML = "";
  for (const [id, provider] of Object.entries(providerDefaults)) {
    const option = document.createElement("option");
    option.value = id;
    option.textContent = provider.label || id;
    providerSelect.append(option);
  }
  providerSelect.value = providerDefaults[currentProvider] ? currentProvider : (data.default_provider || Object.keys(providerDefaults)[0]);
  updateProviderOptions(true);
}

function applyPreset(preset) {
  clearAllMediaInputs();
  const values = preset.values || {};
  for (const [name, value] of Object.entries(values)) {
    const input = field(name);
    if (!input) continue;
    if (input.type === "checkbox") {
      input.checked = ["1", "true", "yes", "on"].includes(String(value).toLowerCase());
    } else if (input.type !== "file") {
      input.value = value;
    }
  }
  updateProviderOptions(true);

savedMedia = mediaSnapshot(preset.media);
  for (const [name, item] of Object.entries(savedMedia)) {
    const input = field(name);
    const drop = input?.closest(".drop");
    if (!drop) continue;
    renderPreview(drop, mediaKind(name), item.url, item.filename);
  }
  const count = Object.keys(savedMedia).length;
  presetHint.textContent = count ? `已读取保存配置：${count} 个素材` : "";
  if (preset.archives) renderArchives(preset.archives);
}

function renderArchives(archives) {
  archiveSelect.innerHTML = "";
  if (!archives || archives.length === 0) {
    const option = document.createElement("option");
    option.value = "";
    option.textContent = "暂无存档";
    archiveSelect.append(option);
    return;
  }
  for (const item of archives) {
    const option = document.createElement("option");
    option.value = item.name;
    option.textContent = item.name;
    archiveSelect.append(option);
  }
}

async function loadArchives() {
  const res = await fetch("/api/archives");
  if (!res.ok) return;
  renderArchives((await res.json()).archives);
}

async function loadPreset() {
  if (isWorkspaceMode() && loadWorkspaceDraft()) return;
  if (isWorkspaceMode()) {
    loadWorkspaceDraft();
    return;
  }
  workspaceName.value = "默认主题";
  const res = await fetch("/api/preset");
  if (!res.ok) return;
  applyPreset(await res.json());
}

function formDataWithSavedMedia() {
  const data = new FormData(form);
  data.set("saved_media", JSON.stringify(savedMedia));
  return data;
}

async function savePreset() {
  presetHint.textContent = "保存中...";
  saveWorkspaceDraft();
  const res = await fetch("/api/preset", { method: "POST", body: formDataWithSavedMedia() });
  const data = await res.json();
  if (!res.ok) {
    presetHint.textContent = data.error || "保存失败";
    return;
  }
  applyPreset(data);
  presetHint.textContent = data.archive ? `已保存为 ${data.archive}` : "已保存当前配置和素材";
}

async function loadArchive() {
  const name = archiveSelect.value;
  if (!name) {
    presetHint.textContent = "请选择一个存档";
    return;
  }
  const data = new FormData();
  data.set("archive_name", name);
  const res = await fetch("/api/archive/load", { method: "POST", body: data });
  const payload = await res.json();
  if (!res.ok) {
    presetHint.textContent = payload.error || "读取失败";
    return;
  }
  applyPreset(payload);
  field("archive_name").value = name;
  presetHint.textContent = `已读取存档：${name}`;
}

async function deleteArchive() {
  const name = archiveSelect.value;
  if (!name) {
    presetHint.textContent = "请选择一个存档";
    return;
  }
  const data = new FormData();
  data.set("archive_name", name);
  const res = await fetch("/api/archive/delete", { method: "POST", body: data });
  const payload = await res.json();
  if (res.ok) {
    renderArchives(payload.archives);
    presetHint.textContent = `已删除存档：${name}`;
  }
}

async function clearPreset() {
  const res = await fetch("/api/preset/clear", { method: "POST" });
  if (!res.ok) return;
  savedMedia = {};
  document.querySelectorAll(".drop").forEach(clearPreview);
  presetHint.textContent = "已清空保存配置";
}

function renderJob(job) {
  statusText.textContent = `${job.status} ${job.done || 0}/${job.total || 0}`;
  eventsEl.textContent = (job.events || []).map((e) => `[${e.time}] ${e.message}`).join("\n");

resultsEl.innerHTML = "";
  for (const result of job.results || []) {
    const card = document.createElement("article");
    card.className = "result";
    const video = document.createElement("video");
    video.controls = true;
    video.src = result.download_url;

const link = document.createElement("a");
    link.href = result.download_url;
    link.download = result.filename;
    link.textContent = "下载视频";

const meta = document.createElement("div");
    meta.className = "meta";
    meta.textContent = `Run ${result.index} · task ${result.task_id} · ${result.local_path}`;

card.append(video, link, meta);
    resultsEl.append(card);
  }

for (const error of job.errors || []) {
    const card = document.createElement("article");
    card.className = "result";
    card.textContent = error;
    resultsEl.append(card);
  }
}

function setActiveTab(tab) {
  const showActivity = tab === "activity";
  mainTabBtn.classList.toggle("isActive", !showActivity);
  activityTabBtn.classList.toggle("isActive", showActivity);
  mainView.classList.toggle("hidden", showActivity);
  activityView.classList.toggle("hidden", !showActivity);
  if (showActivity) loadActivity();
}

function renderActivityStats(counts) {
  const items = [
    ["总记录", counts.total || 0],
    ["页面运行", counts.page || 0],
    ["API 调用", counts.api || 0],
    ["成功", counts.succeeded || 0],
    ["失败", counts.failed || 0],
    ["运行中", counts.running || 0],
  ];
  activityStats.innerHTML = items.map(([label, value]) => (
    `<div class="activityStat"><strong>${value}</strong><span>${label}</span></div>`
  )).join("");
}

function renderActivityList(records) {
  activityList.innerHTML = "";
  if (!records.length) {
    activityList.textContent = "暂无记录";
    return;
  }
  for (const record of records) {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "activityItem";
    button.dataset.id = record.id;
    button.textContent = `${record.source === "api" ? "API" : "页面"} · ${record.status || "unknown"}`;
    const meta = document.createElement("span");
    meta.className = "activityItemMeta";
    meta.textContent = `${record.created_at || ""} · ${record.title || record.job_id || record.id}`;
    button.append(meta);
    button.addEventListener("click", () => loadActivityDetail(record.id, button));
    activityList.append(button);
  }
}

async function loadActivity() {
  const res = await fetch("/api/activity");
  const data = await res.json();
  if (!res.ok) {
    activityDetail.textContent = data.error || "读取后台记录失败";
    return;
  }
  renderActivityStats(data.counts || {});
  renderActivityList(data.records || []);
}

async function loadActivityDetail(id, activeButton) {
  activityList.querySelectorAll(".activityItem").forEach((item) => item.classList.remove("isActive"));
  activeButton?.classList.add("isActive");
  const res = await fetch(`/api/activity/${id}`);
  const data = await res.json();
  activityDetail.innerHTML = "";
  const actions = document.createElement("div");
  actions.className = "rowButtons";
  const restoreBtn = document.createElement("button");
  restoreBtn.type = "button";
  restoreBtn.textContent = "恢复到当前页";
  restoreBtn.disabled = !data.restore;
  restoreBtn.addEventListener("click", () => {
    applyPreset(data.restore);
    saveWorkspaceDraft();
    setActiveTab("main");
    presetHint.textContent = data.restore.warning || "已从后台记录恢复参数和素材";
  });
  actions.append(restoreBtn);
  activityDetail.append(actions);
  if (data.restore?.warning) {
    const warning = document.createElement("p");
    warning.className = "hint";
    warning.textContent = data.restore.warning;
    activityDetail.append(warning);
  }
  const pre = document.createElement("pre");
  pre.textContent = JSON.stringify(data, null, 2);
  activityDetail.append(pre);
}

async function poll(jobId) {
  while (true) {
    const res = await fetch(`/api/jobs/${jobId}`);
    const job = await res.json();
    renderJob(job);
    if (["succeeded", "failed"].includes(job.status)) {
      submitBtn.disabled = false;
      submitBtn.textContent = "开始生成";
      loadActivity();
      return;
    }
    await new Promise((resolve) => setTimeout(resolve, 2500));
  }
}

form.addEventListener("submit", async (event) => {
  event.preventDefault();
  saveWorkspaceDraft();
  submitBtn.disabled = true;
  submitBtn.textContent = "生成中";
  statusText.textContent = "提交中";
  resultsEl.innerHTML = "";
  eventsEl.textContent = "";

const res = await fetch("/api/jobs", { method: "POST", body: formDataWithSavedMedia() });
  const payload = await res.json();
  if (!res.ok) {
    submitBtn.disabled = false;
    submitBtn.textContent = "开始生成";
    statusText.textContent = payload.error || "提交失败";
    return;
  }
  poll(payload.job_id);
});

savePresetBtn.addEventListener("click", savePreset);
clearPresetBtn.addEventListener("click", clearPreset);
loadArchiveBtn.addEventListener("click", loadArchive);
deleteArchiveBtn.addEventListener("click", deleteArchive);
newWorkspaceBtn.addEventListener("click", () => openWorkspace(false));
mainTabBtn.addEventListener("click", () => setActiveTab("main"));
activityTabBtn.addEventListener("click", () => setActiveTab("activity"));
refreshActivityBtn.addEventListener("click", loadActivity);
duplicateWorkspaceBtn.addEventListener("click", async () => {
  duplicateWorkspaceBtn.disabled = true;
  try {
    await openWorkspace(true);
  } catch (error) {
    workspaceHint.textContent = error.message || "复制主题失败";
  } finally {
    duplicateWorkspaceBtn.disabled = false;
  }
});
saveWorkspaceBtn.addEventListener("click", async () => {
  saveWorkspaceBtn.disabled = true;
  try {
    await saveWorkspaceDraft({ persistMedia: true });
  } catch (error) {
    workspaceHint.textContent = error.message || "保存草稿失败";
  } finally {
    saveWorkspaceBtn.disabled = false;
  }
});
form.addEventListener("input", scheduleWorkspaceSave);
form.addEventListener("change", scheduleWorkspaceSave);
field("provider").addEventListener("change", () => updateProviderOptions(false));
closePreviewBtn.addEventListener("click", () => previewDialog.close());
previewDialog.addEventListener("click", (event) => {
  if (event.target === previewDialog) previewDialog.close();
});

chooseOutputBtn.addEventListener("click", async () => {
  chooseOutputBtn.disabled = true;
  try {
    const res = await fetch("/api/choose-output-dir", { method: "POST" });
    const data = await res.json();
    if (res.ok && data.path) field("output_dir").value = data.path;
    else presetHint.textContent = data.error || "未选择目录";
  } finally {
    chooseOutputBtn.disabled = false;
  }
});

appOutputBtn.addEventListener("click", () => {
  field("output_dir").value = "";
});

desktopOutputBtn.addEventListener("click", async () => {
  const res = await fetch("/api/default-output-dir");
  const data = await res.json();
  if (res.ok && data.path) field("output_dir").value = data.path;
});

openOutputBtn.addEventListener("click", async () => {
  openOutputBtn.disabled = true;
  try {
    const data = new FormData();
    data.set("output_dir", field("output_dir").value);
    const res = await fetch("/api/open-output-dir", { method: "POST", body: data });
    const payload = await res.json();
    presetHint.textContent = res.ok ? `已打开输出目录：${payload.path}` : (payload.error || "打开输出目录失败");
  } finally {
    openOutputBtn.disabled = false;
  }
});

cleanCacheBtn.addEventListener("click", async () => {
  cleanCacheBtn.disabled = true;
  try {
    const res = await fetch("/api/cleanup-cache", { method: "POST" });
    const data = await res.json();
    if (res.ok) {
      presetHint.textContent = `已清理缓存：素材 ${data.media_deleted || 0} 个，日志 ${data.logs_deleted || 0} 个`;
    } else {
      presetHint.textContent = data.error || "清理缓存失败";
    }
  } finally {
    cleanCacheBtn.disabled = false;
  }
});

updateProviderOptions(true);
loadConfig();
loadPreset();
loadArchives();

#!/usr/bin/env python3
from __future__ import annotations

import base64
try:
    import cgi  # type: ignore[import-not-found]

    def _parse_form_data(fp, headers, environ=None):
        return cgi.FieldStorage(fp=fp, headers=headers, environ=environ or {"REQUEST_METHOD": "POST"})
except ImportError:
    # Python 3.13+ removed the cgi module (PEP 594).
    # Inline replacement for multipart/form-data parsing.
    from io import BytesIO as _BytesIO
    from urllib.parse import parse_qs as _parse_qs

class _FormParser:
    def __init__(self, fp, headers, environ=None):
        self._items: dict[str, _FieldItem] = {}
        content_type = headers.get("Content-Type", headers.get("content-type", ""))
        body = fp.read()
        if "multipart/form-data" in content_type and isinstance(body, (bytes, bytearray)):
            self._parse_multipart(body, content_type)
        elif isinstance(body, bytes) and body:
            self._parse_urlencoded(body)

def _parse_multipart(self, body: bytes, content_type: str) -> None:
    if isinstance(content_type, bytes):
        content_type = content_type.decode("utf-8", errors="replace")
    match = re.search(r'boundary=("?)([^";\r\n]+)\1', content_type)
    if not match:
        return
    boundary = match.group(2).encode("utf-8")
    delimiter = b"--" + boundary
    parts = body.split(delimiter)
    for part in parts[1:]:
        if part.startswith(b"--"):
            break
        if not part or part in (b"\r\n", b"\n"):
            continue
        if part.startswith(b"\r\n"):
            part = part[2:]
        elif part.startswith(b"\n"):
            part = part[1:]
        header_end = part.find(b"\r\n\r\n")
        body_start = header_end + 4
        if header_end < 0:
            header_end = part.find(b"\n\n")
            body_start = header_end + 2
        if header_end < 0:
            continue
        header_bytes = part[:header_end]
        body_bytes = part[body_start:]
        if body_bytes.endswith(b"\r\n"):
            body_bytes = body_bytes[:-2]
        elif body_bytes.endswith(b"\n"):
            body_bytes = body_bytes[:-1]
        headers_text = header_bytes.decode("utf-8", errors="replace")
        name_m = re.search(r'name="([^"]*)"', headers_text)
        if not name_m:
            continue
        name = name_m.group(1)
        file_m = re.search(r'filename="([^"]*)"', headers_text)
        if file_m:
            self._items[name] = _FieldItem(
                value=body_bytes,
                filename=file_m.group(1),
                file=_BytesIO(body_bytes),
            )
        else:
            self._items[name] = _FieldItem(value=body_bytes.decode("utf-8", errors="replace"))

def _parse_urlencoded(self, body: bytes) -> None:
    for key, values in _parse_qs(body.decode("utf-8", errors="replace")).items():
        self._items[key] = _FieldItem(value=values[0] if values else "")

def api_error(code: str, message: str, detail: str = "", retryable: bool = False) -> dict[str, Any]:
    return {
        "ok": False,
        "error": message,
        "error_detail": detail,
        "error_code": code,
        "error_info": {
            "code": code,
            "message": message,
            "detail": detail,
            "retryable": retryable,
        },
    }

def load_provider_config() -> tuple[dict[str, Any], dict[str, Any] | None]:
    try:
        config = json.loads(PROVIDERS_PATH.read_text(encoding="utf-8"))
        if config.get("schema_version") != 1 or config.get("app") != "nano-banana":
            raise ValueError("providers.json schema_version/app mismatch")
        if not isinstance(config.get("providers"), dict) or not config["providers"]:
            raise ValueError("providers.json providers must be a non-empty object")
        return config, None
    except Exception as exc:
        return FALLBACK_PROVIDERS, {
            "code": "provider_config_error",
            "message": "供应商配置读取失败，请联系维护者",
            "detail": str(exc),
            "retryable": False,
        }

def provider_defaults(config: dict[str, Any], provider: str, model: str = "") -> dict[str, Any]:
    providers = config.get("providers") or {}
    provider_cfg = providers.get(provider) or providers.get(config.get("default_provider")) or next(iter(providers.values()))
    defaults = dict(provider_cfg.get("defaults") or {})
    if provider_cfg.get("base_url"):
        defaults.setdefault("base_url", provider_cfg["base_url"])
    defaults.setdefault("provider", provider)
    models = provider_cfg.get("models") if isinstance(provider_cfg.get("models"), list) else []
    selected = model or str(defaults.get("model") or "")
    for item in models:
        if isinstance(item, dict) and item.get("id") == selected:
            defaults.update(item.get("defaults") or {})
            break
    return defaults

def read_activity_log() -> list[dict[str, Any]]:
    if not ACTIVITY_PATH.exists():
        return []
    try:
        data = json.loads(ACTIVITY_PATH.read_text(encoding="utf-8"))
        return data if isinstance(data, list) else []
    except Exception:
        return []

def write_activity_log(items: list[dict[str, Any]]) -> None:
    STATE_DIR.mkdir(parents=True, exist_ok=True)
    ACTIVITY_PATH.write_text(json.dumps(items[-ACTIVITY_LIMIT:], ensure_ascii=False, indent=2), encoding="utf-8")

def summarize_media_item(item: Any) -> Any:
    if not isinstance(item, dict):
        return item
    result = {key: value for key, value in item.items() if key != "data_url"}
    if item.get("data_url"):
        result["data_url"] = True
        result["chars"] = len(str(item["data_url"]))
    return result

def summarize_payload(value: Any) -> Any:
    if isinstance(value, dict):
        result = {}
        for key, item in value.items():
            if key == "api_key":
                result[key] = mask_key(str(item))
            elif key == "media" and isinstance(item, dict):
                result[key] = {name: summarize_media_item(media_item) for name, media_item in item.items()}
            else:
                result[key] = summarize_payload(item)
        return result
    if isinstance(value, list):
        return [summarize_payload(item) for item in value]
    if isinstance(value, str) and value.startswith("data:"):
        return {"data_url": True, "chars": len(value)}
    return value

def summarize_values_files(values: dict[str, Any], files: dict[str, tuple[str, bytes]]) -> dict[str, Any]:
    return {
        "values": {key: (mask_key(str(value)) if key == "api_key" else value) for key, value in values.items()},
        "files": {key: {"filename": item[0], "bytes": len(item[1])} for key, item in files.items()},
    }

def update_activity(activity_id: str | None, **updates: Any) -> None:
    if not activity_id:
        return
    items = read_activity_log()
    for item in items:
        if item.get("id") == activity_id:
            item.update(updates)
            item["updated_at"] = now_text()
            write_activity_log(items)
            return

def activity_list() -> dict[str, Any]:
    items = read_activity_log()
    summary = []
    counts = {"total": len(items), "page": 0, "api": 0, "succeeded": 0, "failed": 0, "running": 0}
    for item in items:
        source = str(item.get("source") or "")
        status = str(item.get("status") or "")
        if source in counts:
            counts[source] += 1
        if status in counts:
            counts[status] += 1
        summary.append({
            "id": item.get("id"),
            "job_id": item.get("job_id"),
            "source": source,
            "status": status,
            "created_at": item.get("created_at"),
            "updated_at": item.get("updated_at"),
            "title": item.get("title"),
            "request_kind": item.get("request_kind"),
        })
    summary.reverse()
    return {"counts": counts, "records": summary}

def read_json_body(handler: SimpleHTTPRequestHandler, max_bytes: int = 100 * 1024 * 1024) -> dict[str, Any]:
    length = int(handler.headers.get("Content-Length") or "0")
    if length <= 0:
        return {}
    if length > max_bytes:
        raise ValueError(f"JSON body too large: {length} bytes")
    data = json.loads(handler.rfile.read(length).decode("utf-8"))
    if not isinstance(data, dict):
        raise ValueError("JSON body must be an object")
    return data

def decode_data_url(data_url: str) -> tuple[str, bytes]:
    match = re.match(r"^data:([^;,]+)?(;base64)?,(.*)$", data_url, re.DOTALL)
    if not match:
        raise ValueError("Invalid data_url")
    mime = match.group(1) or "application/octet-stream"
    payload = urllib.parse.unquote_to_bytes(match.group(3))
    if match.group(2):
        payload = base64.b64decode(payload)
    return mime, payload

def filename_from_media(field: str, item: dict[str, Any], mime: str = "image/png") -> str:
    raw = str(item.get("filename") or "").strip()
    if raw:
        return Path(raw).name
    if item.get("url"):
        path = urllib.parse.urlparse(str(item["url"])).path
        name = Path(urllib.parse.unquote(path)).name
        if name:
            return name
    suffix = mimetypes.guess_extension(mime) or ".png"
    return f"{field}{suffix}"

def media_item_to_file(field: str, item: Any) -> tuple[str, bytes] | None:
    if item in (None, "", False):
        return None
    if not isinstance(item, dict):
        raise ValueError(f"media.{field} must be an object")
    if item.get("data_url"):
        mime, blob = decode_data_url(str(item["data_url"]))
        return filename_from_media(field, item, mime), blob
    if item.get("url"):
        url = str(item["url"])
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        with urllib.request.urlopen(req, timeout=180, context=_SSL_CONTEXT) as resp:
            blob = resp.read()
            mime = resp.headers.get_content_type() or mimetypes.guess_type(url)[0] or "image/png"
        if not blob:
            raise ValueError(f"media.{field} url returned empty content")
        return filename_from_media(field, item, mime), blob
    raise ValueError(f"media.{field} must include data_url or url")

def load_default_key() -> str:
    env_key = os.environ.get("NANO_BANANA_API_KEY") or os.environ.get("BANANA_API_KEY")
    if env_key:
        return env_key.strip()
    if DEFAULT_CONFIG.exists():
        try:
            data = json.loads(DEFAULT_CONFIG.read_text(encoding="utf-8"))
            return str(data.get("api_key") or data.get("zhenzhen", {}).get("apikey") or "").strip()
        except Exception:
            return ""
    return ""

def request_json(method: str, url: str, api_key: str, body: dict[str, Any] | None = None, timeout: int = 180) -> dict[str, Any]:
    headers = {"Authorization": f"Bearer {api_key}"}
    data = None
    if body is not None:
        headers["Content-Type"] = "application/json"
        data = json.dumps(body, ensure_ascii=False).encode("utf-8")
    req = urllib.request.Request(url, data=data, headers=headers, method=method)
    try:
        with urllib.request.urlopen(req, timeout=timeout, context=_SSL_CONTEXT) as resp:
            raw = resp.read().decode("utf-8", errors="replace")
            return json.loads(raw) if raw else {}
    except urllib.error.HTTPError as exc:
        raw = exc.read().decode("utf-8", errors="replace")
        raise RuntimeError(f"HTTP {exc.code}: {raw}") from exc
    except (urllib.error.URLError, OSError) as exc:
        raise RuntimeError(
            f"无法连接到 API 服务器（{url}），可能是网络问题、API 地址不可达、或者服务器主动断开了连接。"
            f" 原始错误：{exc}"
        ) from exc

def get_field(form: cgi.FieldStorage | dict[str, Any], name: str, default: str = "") -> str:
    item = form[name] if name in form else None
    if item is None or getattr(item, "filename", None):
        return default
    return str(item.value)

def get_file(form: cgi.FieldStorage | dict[str, Any], name: str) -> tuple[str, bytes] | None:
    item = form[name] if name in form else None
    if item is None or not getattr(item, "filename", None):
        return None
    blob = item.file.read()
    return (Path(item.filename).name, blob) if blob else None

def read_preset() -> dict[str, Any]:
    if PRESET_PATH.exists():
        try:
            data = json.loads(PRESET_PATH.read_text(encoding="utf-8"))
            data.setdefault("values", {})
            data.setdefault("media", {})
            return data
        except Exception:
            pass
    return {"values": {}, "media": {}}

def preset_to_client(data: dict[str, Any]) -> dict[str, Any]:
    media = {}
    for field, item in data.get("media", {}).items():
        path = MEDIA_DIR / item.get("stored", "")
        if path.exists():
            stored = path.name
            media[field] = {
                "filename": item.get("filename", path.name),
                "mime": item.get("mime", mimetypes.guess_type(path.name)[0] or "image/png"),
                "stored": stored,
                "url": f"/api/media/{urllib.parse.quote(stored)}?v={int(path.stat().st_mtime)}",
            }
    return {"values": data.get("values", {}), "media": media}

def copy_files_to_restore(values: dict[str, Any], files: dict[str, tuple[str, bytes]], prefix: str) -> dict[str, Any]:
    safe_values = {
        key: value for key, value in values.items()
        if key not in {"api_key", "saved_media", "_auto_seed_base"}
    }
    media: dict[str, Any] = {}
    MEDIA_DIR.mkdir(parents=True, exist_ok=True)
    try:
        saved_media = json.loads(str(values.get("saved_media") or "{}"))
    except Exception:
        saved_media = {}
    if isinstance(saved_media, dict):
        for key, item in saved_media.items():
            if key not in FILE_FIELDS or not isinstance(item, dict):
                continue
            stored = Path(str(item.get("stored", ""))).name
            if stored and (MEDIA_DIR / stored).exists():
                media[key] = {
                    "filename": item.get("filename", stored),
                    "stored": stored,
                    "mime": item.get("mime") or mimetypes.guess_type(stored)[0] or "image/png",
                }
    for key, file_data in files.items():
        if key not in FILE_FIELDS:
            continue
        filename, blob = file_data
        if not blob:
            continue
        suffix = Path(filename).suffix or mimetypes.guess_extension(mimetypes.guess_type(filename)[0] or "") or ".png"
        stored = f"{prefix}_{uuid.uuid4().hex}_{key}{suffix}"
        (MEDIA_DIR / stored).write_bytes(blob)
        media[key] = {
            "filename": filename,
            "stored": stored,
            "mime": mimetypes.guess_type(filename)[0] or "image/png",
        }
    return {"values": safe_values, "media": media}

def activity_record_for_client(record: dict[str, Any] | None) -> dict[str, Any] | None:
    if not record:
        return None
    data = json.loads(json.dumps(record))
    if isinstance(data.get("restore"), dict):
        data["restore"] = preset_to_client(data["restore"])
        return data
    request = data.get("request") or {}
    values = ((request.get("parsed") or {}).get("values") or request.get("values") or {})
    if isinstance(values, dict) and values:
        media: dict[str, Any] = {}
        try:
            saved_media = json.loads(str(values.get("saved_media") or "{}"))
        except Exception:
            saved_media = {}
        if isinstance(saved_media, dict):
            for key, item in saved_media.items():
                if key not in FILE_FIELDS or not isinstance(item, dict):
                    continue
                stored = Path(str(item.get("stored", ""))).name
                if stored and (MEDIA_DIR / stored).exists():
                    media[key] = {
                        "filename": item.get("filename", stored),
                        "stored": stored,
                        "mime": item.get("mime") or mimetypes.guess_type(stored)[0] or "image/png",
                    }
        legacy = preset_to_client({"values": {
            key: value for key, value in values.items()
            if key not in {"api_key", "saved_media"} and key not in FILE_FIELDS
        }, "media": media})
        data["restore"] = {
            **legacy,
            "warning": "" if legacy.get("media") else "这条旧记录没有保存素材副本，只能恢复参数。",
        }
    return data

def parse_saved_media(form: cgi.FieldStorage | dict[str, Any]) -> dict[str, Any]:
    try:
        data = json.loads(get_field(form, "saved_media", "{}"))
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}

def get_file_or_saved(form: cgi.FieldStorage | dict[str, Any], name: str) -> tuple[str, bytes] | None:
    uploaded = get_file(form, name)
    if uploaded:
        return uploaded
    saved = parse_saved_media(form).get(name)
    if not isinstance(saved, dict):
        return None
    stored = Path(str(saved.get("stored", ""))).name
    if stored:
        path = MEDIA_DIR / stored
        if path.exists():
            return (saved.get("filename", path.name), path.read_bytes())
    item = read_preset().get("media", {}).get(name)
    if not item:
        return None
    path = MEDIA_DIR / item.get("stored", "")
    return (item.get("filename", path.name), path.read_bytes()) if path.exists() else None

def collect_media_from_form(form: cgi.FieldStorage) -> dict[str, Any]:
    preset = read_preset()
    active_media = preset.get("media", {})
    saved_media = parse_saved_media(form)
    media = {}
    for key, item in saved_media.items():
        if not isinstance(item, dict):
            continue
        stored = Path(str(item.get("stored", ""))).name
        if stored and (MEDIA_DIR / stored).exists():
            media[key] = {
                "filename": item.get("filename", stored),
                "stored": stored,
                "mime": item.get("mime") or mimetypes.guess_type(stored)[0] or "image/png",
            }
        elif key in active_media:
            media[key] = active_media[key]
    MEDIA_DIR.mkdir(parents=True, exist_ok=True)
    for key in FILE_FIELDS:
        file_data = get_file(form, key)
        if not file_data:
            continue
        filename, blob = file_data
        suffix = Path(filename).suffix or ".png"
        stored = f"{uuid.uuid4().hex}_{key}{suffix}"
        (MEDIA_DIR / stored).write_bytes(blob)
        media[key] = {"filename": filename, "stored": stored, "mime": mimetypes.guess_type(filename)[0] or "image/png"}
    return media

def collect_workspace_snapshot_from_form(form: cgi.FieldStorage) -> dict[str, Any]:
    values = {key: get_field(form, key) for key in VALUE_FIELDS if key in form and not getattr(form[key], "filename", None)}
    return {"values": values, "media": collect_media_from_form(form)}

def safe_archive_name(raw: str) -> str:
    name = re.sub(r"[^A-Za-z0-9_\-\u4e00-\u9fff]+", "_", (raw or "").strip()).strip("_")
    return name[:80] or time.strftime("nano_banana_%Y%m%d_%H%M%S")

def list_archives() -> list[dict[str, Any]]:
    ARCHIVE_DIR.mkdir(parents=True, exist_ok=True)
    return [{"name": p.stem, "filename": p.name, "size": p.stat().st_size, "updated_at": int(p.stat().st_mtime)}
            for p in sorted(ARCHIVE_DIR.glob("*.nanobanana"), key=lambda x: x.stat().st_mtime, reverse=True)]

def save_archive_file(name: str, preset: dict[str, Any]) -> Path:
    ARCHIVE_DIR.mkdir(parents=True, exist_ok=True)
    path = archive_path(name)
    with zipfile.ZipFile(path, "w", compression=zipfile.ZIP_DEFLATED) as zf:
        zf.writestr("preset.json", json.dumps(preset, ensure_ascii=False, indent=2))
        for _, item in preset.get("media", {}).items():
            src = MEDIA_DIR / item.get("stored", "")
            if src.exists():
                zf.write(src, f"media/{src.name}")
    return path

def resolve_output_dir(raw: str | None) -> Path:
    path = Path(raw.strip()).expanduser() if raw and raw.strip() else OUTPUT_DIR
    path.mkdir(parents=True, exist_ok=True)
    return path.resolve()

def unique_output_path(path: Path) -> Path:
    if not path.exists():
        return path
    stem = path.stem
    suffix = path.suffix
    for i in range(2, 1000):
        candidate = path.with_name(f"{stem}_{i}{suffix}")
        if not candidate.exists():
            return candidate
    return path.with_name(f"{stem}_{uuid.uuid4().hex[:8]}{suffix}")

def desktop_output_dir() -> str:
    desktop = Path.home() / "Desktop"
    parent = desktop if desktop.exists() else Path.home()
    return str((parent / "NanoBanana_outputs").resolve())

def open_output_dir(raw: str | None) -> str:
    path = resolve_output_dir(raw)
    if sys.platform == "darwin":
        subprocess.Popen(["open", str(path)])
    elif sys.platform.startswith("win"):
        os.startfile(str(path))  # type: ignore[attr-defined]
    else:
        subprocess.Popen(["xdg-open", str(path)])
    return str(path)

def collect_media(media: Any) -> None:
    if not isinstance(media, dict):
        return
    for item in media.values():
        if not isinstance(item, dict):
            continue
        stored = Path(str(item.get("stored", ""))).name
        if stored:
