def collect_saved_media(values: Any) -> None:
    if not isinstance(values, dict):
        return
    try:
        saved = json.loads(str(values.get("saved_media") or "{}"))
    except Exception:
        saved = {}
    collect_media(saved)

collect_media(read_preset().get("media"))
for record in read_activity_log():
