h2 { margin: 0 0 12px; font-size: 15px; font-weight: 720; }
section { margin-bottom: 22px; }

label {
  display: grid;
  gap: 6px;
  margin-bottom: 12px;
  font-size: 12px;
  font-weight: 650;
  color: #4b5565;
}

input, select, textarea {
  width: 100%;
  border: 1px solid #cbd2dd;
